# Upload financial report
uploaded = client.beta.files.upload(
    file=("annual_report.pdf", open("annual_report.pdf", "rb"), "application/pdf")
)

# Extract data from charts
response = client.beta.messages.create(
    model="claude-opus-4-8",
    messages=[{
        "role": "user",
        "content": [
            {"type": "text", "text": "Extract all data from charts and graphs:
- Revenue trends over time
- Regional breakdown percentages
- Key metrics with exact values

Return as JSON with categories and values."},
            {"type": "document", "source": {"type": "file", "file_id": uploaded.id}}
        ]
    }]
)

# Split 500-page document into 5 chunks
chunks = split_pdf_into_chunks("paper.pdf", chunk_size=100)

file_ids = []
for chunk in chunks:
    uploaded = client.beta.files.upload(
        file=(f"chunk_{i}.pdf", chunk, "application/pdf")
    )
    file_ids.append(uploaded.id)

# Summarize all chunks together
response = client.messages.create(
    messages=[{
        "content": [
            {"type": "text", "text": "Summarize entire paper"},
            *[{"type": "document", "source": {"type": "file", "file_id": fid}} for fid in file_ids]
        ]
    }]
)
